import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val nInt = n.toInt()
    val totalNodes = 2 * nInt
    val graph = Array(totalNodes) { mutableListOf<Pair<Int, Long>>() }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        graph[u].add(Pair(v, w))
        graph[u].add(Pair(v + nInt, w))
    }

    for (u in 0 until nInt) {
        for ((v, w) in graph[u]) {
            if (v >= nInt) {
                val originalNode = v - nInt
                for ((x, cost) in graph[originalNode]) {
                    if (x < nInt) {
                        graph[v].add(Pair(x, 2 * cost))
                    }
                }
            }
        }
    }

    val dist = LongArray(totalNodes) { Long.MAX_VALUE }
    val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
    dist[0] = 0
    pq.add(Pair(0, 0))

    while (pq.isNotEmpty()) {
        val (d, node) = pq.poll()
        if (d != dist[node]) continue
        for ((neighbor, weight) in graph[node]) {
            val newDist = d + weight
            if (newDist < dist[neighbor]) {
                dist[neighbor] = newDist
                pq.add(Pair(newDist, neighbor))
            }
        }
    }

    val answer = minOf(
        dist[nInt - 1],
        dist[2 * nInt - 1],
        dist[(nInt - 1) + nInt]
    )

    return if (answer == Long.MAX_VALUE) -1 else answer
}
```

